import requests
import numpy as np


class OSRMClient:
    # max 9 before codetoobig
    MATCH_CHUNK_SIZE = 9
    OVERLAP = 2
    RADIUS = 25  # meters

    def __init__(self, url="http://router.project-osrm.org"):
        self.url = url

    def _coords_to_string(self, coords):
        return ";".join(f"{c['lon']},{c['lat']}" for c in coords)

    def _dedup(self, coords):
        unique, index_map = [], []
        for c in coords:
            if unique and unique[-1]["lat"] == c["lat"] and unique[-1]["lon"] == c["lon"]:
                index_map.append(len(unique) - 1)
            else:
                unique.append(c)
                index_map.append(len(unique) - 1)
        return unique, index_map

    def _chunks(self, coords):
        n = len(coords)
        if n == 0:
            return
        stride = self.MATCH_CHUNK_SIZE - self.OVERLAP
        i = 0
        while True:
            end = min(i + self.MATCH_CHUNK_SIZE, n)
            skip = 0 if i == 0 else self.OVERLAP
            yield coords[i:end], skip
            if end == n:
                return
            i += stride

    def _match(self, chunk):
        ts_seconds = [int(c['timestamp']) // 1000 for c in chunk]
        for i in range(1, len(ts_seconds)):
            if ts_seconds[i] <= ts_seconds[i - 1]:
                ts_seconds[i] = ts_seconds[i - 1] + 1

        response = requests.get(
            f"{self.url}/match/v1/driving/{self._coords_to_string(chunk)}",
            params={
                "geometries": "geojson",
                "overview": "full",
                "tidy": "true",
                "radiuses": ";".join(str(self.RADIUS) for _ in chunk),
                "timestamps": ";".join(str(t) for t in ts_seconds),
            },
            timeout=15,
        )
        if not response.ok:
            raise RuntimeError(f"OSRM {response.status_code}: {response.text}")
        data = response.json()
        if data.get("code") != "Ok":
            raise RuntimeError(f"OSRM match failed: {data.get('code')} — {data.get('message', '')}")

        snapped = []
        for original, tp in zip(chunk, data["tracepoints"]):
            if tp is None:
                snapped.append({**original, "snapped": False})
            else:
                lon, lat = tp["location"]
                snapped.append({**original, "lat": lat, "lon": lon, "snapped": True})
        return snapped

    def snap(self, coords: list[dict]) -> list[dict]:
        unique, index_map = self._dedup(coords)
        if len(unique) < 2:
            return [{**c, "snapped": False} for c in coords]

        snapped_unique = []
        for chunk, skip in self._chunks(unique):
            snapped_unique.extend(self._match(chunk)[skip:])

        return [snapped_unique[i] for i in index_map]
    
